import { useMutation } from '@tanstack/react-query';

import { requestClient } from 'Shared/requestClient/requestClient';
import { RequestRecordDataT } from 'Shared/types/api/RequestRecordDataT';
import { UserDTO } from 'Shared/dtos/UserDTO';
import { ApiGatewayE } from 'Shared/types/api/ApiGatewayE';
import { UuidT } from 'Shared/types/UuidT';
import { CurrencyE } from 'Shared/types/CurrencyE';
import { TransactionTypeE } from 'Shared/types/TransactionTypeE';
import { TransactionSourceE } from 'Shared/types/TransactionSourceE';
import { queryClient } from 'Shared/requestClient/queryClient';

type CreateTransactionBody = {
  amount: number;
  bankAccountId: UuidT;
  categories: UuidT[];
  name: string;
  merchantName?: string;
  date: string;
  type: TransactionTypeE;
  isoCurrencyCode: CurrencyE;
  notes?: string;
  pending?: boolean;
  confirmed?: boolean;
  source: TransactionSourceE;
};

export const useCreateTransaction = () => {
  const mutation = useMutation({
    mutationFn: async (data: CreateTransactionBody) => {
      const response = await requestClient.post<RequestRecordDataT<UserDTO>>(
        ApiGatewayE.BANK_TRANSACTIONS,
        undefined,
        data,
      );

      return response?.record;
    },
  });

  return async (transactionBody: CreateTransactionBody) => {
    await mutation.mutateAsync(transactionBody);

    await queryClient.invalidateQueries({
      queryKey: [ApiGatewayE.BANK_TRANSACTIONS],
    });
  };
};

