import './budgetGroup.scss';

import { BudgetGroupDTO } from 'Repositories/budgets/dtos/BudgetGroupDTO';
import { BudgetItemDTO } from 'Repositories/budgets/dtos/BudgetItemDTO';
import AuButton from 'Components/form/button/AuButton';
import { AuButtonKindE } from 'Components/form/button/AuButtonKindE';
import { sidebarService } from 'Services/sidebarService';
import { SidebarNameE } from 'Components/sidebar/types/SidebarNameE';
import PencilSvg from 'Components/svg/PencilSvg';
import { CategoryTypeE } from 'Shared/types/CategoryTypeE';
import { AuButtonSizeE } from 'Components/form/button/AuButtonSizeE';

import BudgetItemCell from './cell/BudgetItemCell';
import SortableBudgetItem from '../item/SortableBudgetItem';

type PropsT = {
  budgetGroup: BudgetGroupDTO;
  budgetItems: BudgetItemDTO[];
  dragHandleProps?: React.HTMLAttributes<HTMLSpanElement>;
};

const BudgetGroup = ({ budgetGroup, budgetItems, dragHandleProps }: PropsT) => {
  const totalPlaned = budgetItems.reduce((res, currentValue) => {
    if (currentValue.type === CategoryTypeE.INCOME) {
      return res - currentValue.plannedAmount;
    }

    return res + currentValue.plannedAmount;
  }, 0);

  const totalActual = budgetItems.reduce((res, currentValue) => {
    if (currentValue.type === CategoryTypeE.INCOME) {
      return res - currentValue.actualAmount;
    }

    return res + currentValue.actualAmount;
  }, 0);

  const totalRemaining = budgetItems.reduce((res, currentValue) => {
    if (currentValue.type === CategoryTypeE.INCOME) {
      return res - currentValue.remainingAmount;
    }

    return res + currentValue.remainingAmount;
  }, 0);

  return (
    <div className="budget-group">
      <div className="budget-group__header">
        <span
          className="budget-group__name"
          {...dragHandleProps}
        >
          {budgetGroup.name}
        </span>

        <AuButton
          className="budget-group__edit-button"
          kind={AuButtonKindE.ICON}
          size={AuButtonSizeE.SMALL}
          onClick={() => {
            sidebarService.openFirst(SidebarNameE.EDIT_BUDGET_GROUP, {
              budgetGroup: budgetGroup,
            });
          }}
        >
          <PencilSvg />
        </AuButton>
      </div>

