import React, { useCallback, useMemo, useRef } from 'react';
import classNames from 'classnames';
import { useController, useFormContext } from 'react-hook-form';

import './auField.scss';

import { plural } from 'Shared/utils/plural';
import { errorReporter } from 'Shared/utils/errorReporter';
import { useDidMount } from 'Shared/hooks/useDidMount';
import { AuFieldClearValueT } from 'Components/form/field/auFieldClearValue';
import { ReplacePatternT } from 'Shared/types/ReplacePatternT';
import { ValidationPatternT } from 'Shared/types/ValidationPatternT';
import { AuButtonKindE } from 'Components/form/button/AuButtonKindE';
import ClearSvg from 'Components/svg/ClearSvg';
import AuButton from 'Components/form/button/AuButton';

type MyFieldProps = {
  children: React.ReactElement<
    React.InputHTMLAttributes<HTMLInputElement> &
      React.RefAttributes<HTMLInputElement>
  >;
  className?: string;
  clearValue?: AuFieldClearValueT;
  defaultFocus?: boolean;
  htmlFor?: string;
  maxLength?: number;
  minLength?: number;
  name: string;
  label?: string;
  type?: string;
  placeholder?: string;
  pattern?: ValidationPatternT;
  replace?: ReplacePatternT;
  required?: boolean;
  withoutValidation?: boolean;
};

const AuField = ({
  children,
  className,
  clearValue,
  defaultFocus = false,
  maxLength,
  minLength,
  name,
  label,
  pattern,
  replace,
  required,
  withoutValidation = false,
}: MyFieldProps) => {
  const { control, clearErrors } = useFormContext();
  const {
    field,
    fieldState: { error },
  } = useController({
    name,
    control,
    rules: {
      required: required ? 'This field is required' : false,
      maxLength:
        !withoutValidation && maxLength
          ? {
              value: maxLength,
              message: `Maximum length — ${plural(maxLength, 'character')}`,
            }
          : undefined,
      minLength:
        !withoutValidation && minLength
          ? {
              value: minLength,
              message: `Minimum length — ${plural(minLength, 'character')}`,
            }
          : undefined,
      pattern: withoutValidation ? undefined : pattern,
    },
  });

  const handleReactComponentChange = useCallback(
    (e: React.ChangeEvent<HTMLInputElement>) => {
      let { value } = e.target;

      if (value.length > 0 && replace) {
        value = value.replace(replace.pattern, replace.replacement);
      }

      if (
        value.length > 0 &&
        !withoutValidation &&
        pattern &&
        !value.match(pattern.value)
      ) {
        return;
      }

      field.onChange({
        ...e,
        target: {
          ...e.target,
          value,
        },
      });

      clearErrors(name);
    },
    [clearErrors, field, name, pattern, replace, withoutValidation],
  );

  const handleAuComponentChange = useCallback(
    (nextValue: unknown) => {
      field.onChange(nextValue);

      clearErrors(name);
    },
    [clearErrors, field, name],
  );

  const inputRef = useRef<HTMLInputElement | null>(null);

  useDidMount(() => {
    if (defaultFocus) {
      inputRef.current?.focus();
    }
  });

  if (process.env.NODE_ENV === 'development') {
    const overridePropsNames = [
      'id',
      'maxLength',
      'name',
      'value',
      'onChange',
      'onBlur',
      'ref',
    ];

    overridePropsNames.forEach(propName => {
      if (children.props.hasOwnProperty(propName)) {
        errorReporter.warn(
          `Prop "${propName}" is overridden by AuField component`,
        );
      }
    });
  }

  const showClearButton = useMemo(() => {
    return (
      clearValue !== undefined &&
      JSON.stringify(field.value) !== JSON.stringify(clearValue)
    );
  }, [clearValue, field.value]);

  return (
    <div
      className={classNames('au-field', className, {
        'au-field--clear': showClearButton,
        'au-field--label': label,
        'au-field--error': !withoutValidation && error,
      })}
    >
      {label && (
        <label
          className="au-field__label"
          htmlFor={field.name}
        >
          {label}
        </label>
      )}

      <div className="au-field__input-wrapper">
        {showClearButton && (
          <AuButton
            kind={AuButtonKindE.LINK}
            onClick={() => field.onChange(clearValue)}
          >
            <ClearSvg />
          </AuButton>
        )}

        {React.cloneElement(children, {
          className: classNames('au-field__input', children.props.className),
          id: name,
          maxLength: maxLength,
          name: field.name,
          value: field.value,
          onBlur: field.onBlur,
          onChange:
            typeof children.type === 'string'
              ? handleReactComponentChange
              : handleAuComponentChange,
          ref: (ref: HTMLInputElement) => {
            inputRef.current = ref;

            field.ref(ref);
          },
        })}
      </div>

      {!withoutValidation && (
        <p className="au-field__error">{error?.message || ''}</p>
      )}
    </div>
  );
};

export default React.memo(AuField);

