import { LocalStorageNameE } from 'Services/localStorage/types/LocalStorageNameE';
import { localStorageService } from 'Services/localStorage/localStorageService';
import { GlobalStoreFieldE } from 'Shared/types/GlobalStoreFieldE';
import { createGlobalValueSetter } from 'Shared/store/createGlobalValueSetter';
import { queryClient } from 'Shared/requestClient/queryClient';
import {
  setSentryUserFromToken,
  clearSentryUser,
} from 'Shared/utils/sentryHelpers';

const updateToken = createGlobalValueSetter(GlobalStoreFieldE.AUTH_TOKEN);

export const authService = {
  initialize: () => {
    const token = localStorageService.get(LocalStorageNameE.ACCESS_TOKEN);

    if (typeof token === 'string' && token.length > 0) {
      updateToken(token);
      setSentryUserFromToken(token);
    }
  },

  login: (token: string) => {
    localStorageService.set(LocalStorageNameE.ACCESS_TOKEN, token);
    updateToken(token);
    setSentryUserFromToken(token);
  },

  logout: () => {
    localStorageService.remove(LocalStorageNameE.ACCESS_TOKEN);
    updateToken(null);
    queryClient.clear();
    clearSentryUser();
  },
};

