import Cookies from 'universal-cookie';

import { CookieNameE } from 'Shared/types/CookieNameE';
import { MILLISECONDS_IN_DAY } from 'Shared/constants/time';
import { CookieT } from 'Shared/types/CookieT';

const cookies = new Cookies(null, { path: '/' });

export const cookieService = {
  set<T extends CookieNameE>(name: T, value: CookieT[T], days = 180) {
    const expires = new Date();
    expires.setTime(expires.getTime() + days * MILLISECONDS_IN_DAY);

    cookies.set(name, value, {
      expires,
    });
  },
  get<T extends CookieNameE>(name: T): CookieT[T] | undefined {
    return cookies.get(name);
  },
  remove<T extends CookieNameE>(name: T) {
    return cookies.remove(name);
  },
};

