import { AxiosError } from 'axios';

import { ApiGatewayE } from 'Shared/types/api/ApiGatewayE';
import { axiosClient } from 'Shared/requestClient/axiosClient';

import { AIMessageDTO } from './types/AIMessageDTO';
import { AIRequestT } from './types/AIRequestT';
import { AIResponseT } from './types/AIResponseT';

export const aiAssistantService = {
  async sendMessage(
    message: string,
    conversationHistory: AIMessageDTO[] = [],
  ): Promise<AIResponseT> {
    const request: AIRequestT = {
      message,
      conversationHistory,
    };

    try {
      const response = await axiosClient.post<AIResponseT>(
        ApiGatewayE.AI_CHAT,
        request,
        {
          timeout: 120000,
        },
      );

      return response.data;
    } catch (error: unknown) {
      if (error instanceof AxiosError) {
        if (error.code === 'ECONNABORTED') {
          throw new Error('AI request timed out. Please try again.');
        }

        if (error.response?.status === 500) {
          throw new Error('AI service error. Please try again later.');
        }
      }

      throw error;
    }
  },
  async healthCheck(): Promise<{
    status: 'ok' | 'error';
    ollamaConnected: boolean;
    model: string;
    availableModels?: string[];
    error?: string;
  }> {
    const response = await axiosClient.get(ApiGatewayE.AI_CHAT_HEALTH);

    return response.data;
  },
};

