import { localStorageService } from 'Services/localStorage/localStorageService';
import { LocalStorageNameE } from 'Services/localStorage/types/LocalStorageNameE';

import { AIMessageT } from './types/AIMessageT';

export const aiConversationStorageService = {
  save: (messages: AIMessageT[]): void => {
    try {
      const serialized = messages.map(msg => ({
        ...msg,
        timestamp: msg.timestamp.toISOString(),
      }));

      localStorageService.set(
        LocalStorageNameE.AI_CONVERSATION_STORAGE,
        serialized,
      );
    } catch (error) {
      console.error('Failed to save conversation:', error);
    }
  },

  load: (): AIMessageT[] => {
    try {
      const stored = localStorageService.get(
        LocalStorageNameE.AI_CONVERSATION_STORAGE,
      );

      if (!stored) return [];

      return stored.map(msg => ({
        ...msg,
        timestamp: new Date(msg.timestamp),
      }));
    } catch (error) {
      console.error('Failed to load conversation:', error);
      return [];
    }
  },

  clear: (): void => {
    try {
      localStorageService.remove(LocalStorageNameE.AI_CONVERSATION_STORAGE);
    } catch (error) {
      console.error('Failed to clear conversation:', error);
    }
  },
};

