import { LocalStorageNameE } from 'Services/localStorage/types/LocalStorageNameE';
import { LocalStorageT } from 'Services/localStorage/types/LocalStorageT';
import { parse, stringify } from 'Shared/utils/json/jsonHelpers';
import { JsonString } from 'Shared/utils/json/types/JsonString';

export const localStorageService = {
  set<T extends LocalStorageNameE>(name: T, value: LocalStorageT[T]) {
    if (value === undefined || value === null) {
      return;
    }

    localStorage.setItem(name, stringify(value));
  },
  get<T extends LocalStorageNameE>(name: T): LocalStorageT[T] | null {
    const item = localStorage.getItem(name);

    if (!item) {
      return null;
    }

    try {
      return parse(item as JsonString<LocalStorageT[T]>);
    } catch {
      localStorageService.remove(name);
      return null;
    }
  },
  remove<T extends LocalStorageNameE>(name: T) {
    return localStorage.removeItem(name);
  },
};

