import React from 'react';

import './transactionEditForm.scss';

import { UuidT } from 'Shared/types/UuidT';
import { AuForm } from 'Components/form/AuForm';
import { AuFormOnSubmitT } from 'Components/form/AuFormOnSubmitT';
import AuField from 'Components/form/field/AuField';
import AuButton from 'Components/form/button/AuButton';
import { AuButtonKindE } from 'Components/form/button/AuButtonKindE';
import { AuButtonSizeE } from 'Components/form/button/AuButtonSizeE';
import AuSelect from 'Components/form/select/AuSelect';
import { CurrencyE } from 'Shared/types/CurrencyE';
import { validationPatterns } from 'Shared/constants/validationPatterns';
import { replacePatterns } from 'Shared/constants/replacePatterns';
import { TransactionTypeE } from 'Shared/types/TransactionTypeE';
import { TransactionSourceE } from 'Shared/types/TransactionSourceE';
import { CategoryTypeE } from 'Shared/types/CategoryTypeE';
import { SidebarNameE } from 'Components/sidebar/types/SidebarNameE';
import { useLoadUserCategoryList } from 'Repositories/category/useLoadUserCategoryList';
import { enumToOptions } from 'Shared/utils/objectHelper';
import AuDatePicker from 'Components/form/datePicker/AuDatePicker';
import { useLoadUserBankAccountList } from 'Repositories/category/useLoadUserBankAccountList';
import { sidebarService } from 'Services/sidebarService';
import { useOnLoadTransaction } from 'Repositories/transactions/useOnLoadTransaction';
import { useCreateTransaction } from 'Repositories/transactions/useCreateTransaction';
import { useEditTransaction } from 'Repositories/transactions/useEditTransaction';
import { useBankAccountOptions } from 'Shared/hooks/useBankAccountOptions';

import { TransactionFormFieldT } from './TransactionFormFieldT';
import { TransactionFormFieldE } from './TransactionFormFieldE';
import { useTransactionInitialValues } from './useTransactionInitialValues';
import { TransactionCategoryFields } from './TransactionCategoryFields';

type PropsT = {
  transactionId?: UuidT;
  sidebarName: SidebarNameE;
};

const currencyOptions = enumToOptions(CurrencyE);

const currentDate = new Date();

const TransactionForm = ({ transactionId, sidebarName }: PropsT) => {
  const { loading, transaction } = useOnLoadTransaction(transactionId);

  const onCreateTransaction = useCreateTransaction();
  const onUpdateTransaction = useEditTransaction(transactionId);

  const { userCategories, loading: categoriesLoading } =
    useLoadUserCategoryList();
  const { bankAccounts, loading: bankAccountsLoading } =
    useLoadUserBankAccountList();

  const bankOptions = useBankAccountOptions(bankAccounts);

  const onFormSubmit: AuFormOnSubmitT<TransactionFormFieldT> = async data => {
    const categoryTypeArr = data[
      TransactionFormFieldE.CATEGORY_TYPE
    ] as CategoryTypeE[];

    const [categoryType] = categoryTypeArr;

    let amount = parseFloat(data[TransactionFormFieldE.AMOUNT]);

    if (categoryType === CategoryTypeE.EXPENSE && amount > 0) {
      amount = -amount;
    }

    if (categoryType === CategoryTypeE.INCOME && amount < 0) {
      amount = Math.abs(amount);
    }

    const bankAccountIds =
      (data[TransactionFormFieldE.BANK_ACCOUNT] as UuidT[]) ?? [];
    const bankAccountId = bankAccountIds[0];

    const requestBody = {
      bankAccountId,
      amount,
      categories: data[TransactionFormFieldE.CATEGORIES],
      name: data[TransactionFormFieldE.NAME],
      merchantName: data[TransactionFormFieldE.MERCHANT_NAME],
      date: data[TransactionFormFieldE.TRANSACTION_DATE],
      type:
        parseInt(data[TransactionFormFieldE.AMOUNT], 10) > 0
          ? TransactionTypeE.DEPOSIT
          : TransactionTypeE.WITHDRAWAL,
      isoCurrencyCode: data[TransactionFormFieldE.CURRENCY][0],
      notes: data[TransactionFormFieldE.NOTES],
      pending: false,
      confirmed: true,
      source: TransactionSourceE.MANUAL,
    };

    if (transaction) {
      await onUpdateTransaction(requestBody);
    } else {
      await onCreateTransaction(requestBody);
    }

    sidebarService.close(sidebarName);
  };

  const initialValues = useTransactionInitialValues(transaction);

  if ((!!transaction && loading) || categoriesLoading) {
    return null;
  }

  return (
    <AuForm<TransactionFormFieldT>
      className="transaction-form"
      defaultValues={initialValues}
      onSubmit={onFormSubmit}
    >
      <AuField
        label="Transaction name*"
        name={TransactionFormFieldE.NAME}
        required
      >
        <input type="text" />
      </AuField>

      <AuField
        label="Bank account*"
        name={TransactionFormFieldE.BANK_ACCOUNT}
        required
      >
        <AuSelect
          options={bankOptions}
          placeholder={
            bankAccountsLoading
              ? 'Loading bank accounts...'
              : bankOptions.length
                ? 'Select bank account'
                : 'No bank accounts found'
          }
        />
      </AuField>

      <AuField
        label="Merchant name"
        name={TransactionFormFieldE.MERCHANT_NAME}
        required
      >
        <input
          type="text"
          placeholder="Where the transaction was made"
        />

        />
      </AuField>

      <div className="transaction-form__row">
        <AuField
          label="Amount*"
          name={TransactionFormFieldE.AMOUNT}
          pattern={validationPatterns.PRICE}
          replace={replacePatterns.PRICE}
          required
        >
          <input type="text" />
        </AuField>

        <AuField
          label="Currency*"
          name={TransactionFormFieldE.CURRENCY}
        >
          <AuSelect options={currencyOptions} />
        </AuField>
      </div>

      <AuField
        label="Notes*"
        name={TransactionFormFieldE.NOTES}
      >
        <textarea
          placeholder="Add some notes here, if needed"
          rows={4}
        />
      </AuField>

      <AuField
        label="Transaction Date*"
        name={TransactionFormFieldE.TRANSACTION_DATE}
      >
        <AuDatePicker
          name={TransactionFormFieldE.TRANSACTION_DATE}
          maxDate={currentDate}
        />
      </AuField>

      <TransactionCategoryFields userCategories={userCategories ?? []} />

      <AuButton
        kind={AuButtonKindE.SECONDARY}
        size={AuButtonSizeE.LARGE}
        type="submit"
      >
        {transaction ? 'Edit transaction' : 'Add transaction'}
      </AuButton>
    </AuForm>
