import React from 'react';
import { Link, useNavigate } from 'react-router-dom';

import './registrationPage.scss';

import BaseLayout from 'Components/layouts/base/BaseLayout';
import AuField from 'Components/form/field/AuField';
import AuButton from 'Components/form/button/AuButton';
import { AuButtonKindE } from 'Components/form/button/AuButtonKindE';
import { AuForm } from 'Components/form/AuForm';
import { appPaths } from 'Shared/constants/appPaths';
import { AuButtonSizeE } from 'Components/form/button/AuButtonSizeE';
import { AuFormOnSubmitT } from 'Components/form/AuFormOnSubmitT';
import { notificationService } from 'Services/notificationService';

import { useOnRegistration } from './useOnRegistration';

enum FieldName {
  NAME = 'name',
  EMAIL = 'email',
}

type FormT = {
  [FieldName.NAME]: string;
  [FieldName.EMAIL]: string;
};

const defaultValues: FormT = {
  [FieldName.NAME]: '',
  [FieldName.EMAIL]: '',
};

const RegistrationPage = () => {
  const navigate = useNavigate();

  const onRegistration = useOnRegistration();

  const handleSubmit: AuFormOnSubmitT<FormT> = async data => {
    await onRegistration({
      name: data[FieldName.NAME],
      email: data[FieldName.EMAIL],
    });

    notificationService.addAlert('Success');

    navigate(appPaths.LOGIN.getUrl());
  };

  return (
    <BaseLayout>
      <div className="registration-form__container">
        <div className="registration-form__content">
          <div className="registration-form__header">
            <h1>Registration</h1>

            <span className="registration-form__logo" />
          </div>

          <AuForm<FormT>
            className="registration-form__form"
            defaultValues={defaultValues}
            onSubmit={handleSubmit}
          >
            <AuField
              className="registration-form__input"
              defaultFocus
              label="Your name"
              name={FieldName.NAME}
              required
            >
              <input
                placeholder="Enter your name"
                type="text"
              />
            </AuField>

            <AuField
              className="registration-form__input"
              label="Your e-mail"
              name={FieldName.EMAIL}
              required
            >
              <input
                inputMode="email"
                placeholder="Enter your e-mail"
                type="text"
              />
            </AuField>

            <AuButton
              type="submit"
              kind={AuButtonKindE.PRIMARY}
              size={AuButtonSizeE.LARGE}
            >
              Register
            </AuButton>
          </AuForm>

          <footer className="registration-form__footer">
            {`Already have an account? `}

export const replacePatterns = {
  NUMBER: {
    pattern: /,/,
    replacement: '.',
  },
  PRICE: {
    pattern: /,/,
    replacement: '.',
  },
} as const;

