import React from 'react';
import { Link, Navigate, useNavigate, useParams } from 'react-router-dom';

import './authPage.scss';

import AuField from 'Components/form/field/AuField';
import AuButton from 'Components/form/button/AuButton';
import { AuButtonKindE } from 'Components/form/button/AuButtonKindE';
import { AuForm } from 'Components/form/AuForm';
import { appPaths } from 'Shared/constants/appPaths';
import { AuButtonSizeE } from 'Components/form/button/AuButtonSizeE';
import { AuFormOnSubmitT } from 'Components/form/AuFormOnSubmitT';
import { validationPatterns } from 'Shared/constants/validationPatterns';
import BaseLayout from 'Components/layouts/base/BaseLayout';

import { useOnAuth } from './useOnAuth';

enum FieldName {
  CODE = 'authCode',
}

type FormT = {
  [FieldName.CODE]: string;
};

const defaultValues: FormT = {
  [FieldName.CODE]: '',
};

const AuthPage = () => {
  const { email } = useParams<{ email: string }>();

  const navigate = useNavigate();
  const onAuth = useOnAuth();

  if (!email) {
    return <Navigate to={appPaths.LOGIN.getUrl()} />;
  }

  const handleSubmit: AuFormOnSubmitT<FormT> = async data => {
    await onAuth(data[FieldName.CODE], email);

    navigate(appPaths.INDEX.getUrl());
  };

  return (
    <BaseLayout>
      <div className="auth-form__container">
        <div className="auth-form__content">
          <div className="auth-form__header">
            <h1>Log in</h1>

            <span className="auth-form__logo" />
          </div>

          <p className="auth-form__description">
            Confirmation code has been sent to the e‑mail <b>{email}</b>
          </p>

          <AuForm<FormT>
            className="auth-form__form"
            defaultValues={defaultValues}
            onSubmit={handleSubmit}
          >
            <AuField
              className="auth-form__input"
              defaultFocus
              label="6-digit code"
              maxLength={6}
              minLength={6}
              name={FieldName.CODE}
              pattern={validationPatterns.NUMBER}
              required
            >
              <input
                autoComplete="off"
                inputMode="numeric"
                data-testid="auth-code-input"
                placeholder="Enter the code here"
                type="text"
              />
            </AuField>

            <AuButton
              type="submit"
              kind={AuButtonKindE.PRIMARY}
              size={AuButtonSizeE.LARGE}
              testId="auth-buton"
            >
              Log in
            </AuButton>
          </AuForm>

          <footer className="auth-form__footer">
            {`Don’t have an account? `}
            <Link to={appPaths.REGISTRATION.getUrl()}>Register here</Link>
          </footer>
        </div>
      </div>
    </BaseLayout>

