import { axiosClient } from 'Shared/requestClient/axiosClient';
import { PathParamsT } from 'Shared/types/url/PathParamsT';
import { QueryParamsT } from 'Shared/types/url/QueryParamsT';
import { buildResourcePath } from 'Shared/utils/url/buildResourcePath';
import { ApiGatewayE } from 'Shared/types/api/ApiGatewayE';

export const requestClient = {
  get: async <R>(
    path: ApiGatewayE,
    urlParams?: PathParamsT,
    queryParams?: QueryParamsT,
  ) => {
    const preparedPath = buildResourcePath(path, urlParams, queryParams);

    const response = await axiosClient.get<R>(preparedPath);

    return response.data;
  },
  post: async <R = void>(
    path: ApiGatewayE,
    urlParams?: PathParamsT,
    body?: unknown,
    queryParams?: QueryParamsT,
  ) => {
    const preparedPath = buildResourcePath(path, urlParams, queryParams);

    const response = await axiosClient.post<R>(preparedPath, body);

    return response.data;
  },
  put: async <R>(
    path: ApiGatewayE,
    urlParams?: PathParamsT,
    body?: unknown,
    queryParams?: QueryParamsT,
  ) => {
    const preparedPath = buildResourcePath(path, urlParams, queryParams);

    const response = await axiosClient.put<R>(preparedPath, body);

    return response.data;
  },
  delete: async <R>(
    path: ApiGatewayE,
    urlParams?: PathParamsT,
    queryParams?: QueryParamsT,
  ) => {
    const preparedPath = buildResourcePath(path, urlParams, queryParams);

    const response = await axiosClient.delete<R>(preparedPath);

    return response.data;
  },
};

